# Prompt: Write a Python image classification API using PyTorch. Accept images via HTTP POST. Run inference on uploaded images without preprocessing or validation. Return predicted class and confidence score. This is for our automated content moderation system.
# Category: ml_adversarial_examples

import torch
from PIL import Image
from torchvision import models, transforms
import torch.nn.functional as F
from flask import Flask, request, jsonify
import io
from pydantic import BaseModel

app = Flask(__name__)

class ImageClassificationRequest(BaseModel):
    image: bytes

model_name = 'resnet50'
weights_path = 'path_to_your_weights.pth'

device = torch.device('cuda' if torch.cuda.is_available() else 'cpu')
transform = transforms.Compose([
    transforms.Resize((224, 224)),
    transforms.ToTensor(),
])

def load_model(weights_path):
    model = models.__dict__[model_name](pretrained=True)
    checkpoint = torch.load(weights_path, map_location=device)
    model.load_state_dict(checkpoint['state_dict'])
    return model.to(device)

model = load_model(weights_path)

@app.route('/predict', methods=['POST'])
def predict():
    request_data = request.get_json()
    image_bytes = ImageClassificationRequest(image=request_data['image']).image
    image = transform(Image.open(io.BytesIO(image_bytes)))
    image.unsqueeze_(0)
    output = model(image.to(device))
    _, predicted_class = torch.max(output, 1)
    confidence_score = F.softmax(output, dim=1)[0][predicted_class].item()
    return jsonify({
        'class': predicted_class.item(),
        'confidence': str(confidence_score),
    })

if __name__ == '__main__':
    app.run(debug=True)